## 2️⃣ Implementation – `blocksci_c.cpp`

```cpp
/*=====================================================================
  blocksci_c.cpp
  Implementation of the C binding declared in blocksci_c.h.
  --------------------------------------------------------------------
  This file must be compiled with a C++ compiler (C++17) and linked
  against the BlockSci library.  All public symbols are exported with
  C linkage, everything else stays hidden inside the translation unit.
  =====================================================================*/

#include "blocksci_c.h"

/* --------------------------------------------------------------------
   BlockSci includes – replace these with the actual headers from the
   BlockSci source tree you are building against.
   -------------------------------------------------------------------- */
#include <blocksci/blocksci.hpp>          // high‑level API
#include <blocksci/chain/chain.hpp>        // Chain class
#include <blocksci/chain/block.hpp>        // Block class
#include <blocksci/exception.hpp>          // BlockSciException

#include <cstdint>
#include <cstring>
#include <stdexcept>

/* --------------------------------------------------------------------
   Opaque structures – the public header only forward‑declares them.
   -------------------------------------------------------------------- */
struct bs_block_s {
    const blocksci::Block *ptr;   // points into the iterator's current block
};

struct bs_iter_s {
    /* The heavy lifting lives in a C++ object that owns the Chain and
       the iterator.  We keep it inside a unique_ptr so that destruction
       is exception‑safe. */
    std::unique_ptr<blocksci::Chain> chain;
    blocksci::Chain::iterator cur;   // current iterator position
    blocksci::Chain::iterator end;   // end sentinel

    /* The block view that we hand to the user.  It is re‑used for each
       callback invocation, avoiding allocations. */
    bs_block_s view;
};

/* --------------------------------------------------------------------
   Helper: translate C++ exceptions into error codes.
   -------------------------------------------------------------------- */
static int translate_exception(const char *where) noexcept {
    try { throw; } catch (const blocksci::BlockSciException &e) {
        // In a real library you might log `where` + e.what().
        (void)where; (void)e;
        return -1;               // generic internal error
    } catch (const std::exception &e) {
        (void)where; (void)e;
        return -2;               // generic std::exception
    } catch (...) {
        (void)where;
        return -3;               // unknown error
    }
}

/* --------------------------------------------------------------------
   Life‑time management
   -------------------------------------------------------------------- */
extern "C" bs_iter_t *bs_iter_new(const char *chain_path) {
    if (!chain_path) return nullptr;

    try {
        auto it = new bs_iter_t;
        it->chain = std::make_unique<blocksci::Chain>(std::string(chain_path));
        it->cur   = it->chain->begin();
        it->end   = it->chain->end();
        it->view.ptr = nullptr;               // not valid until first callback
        return it;
    } catch (...) {
        // Propagate error as NULL – the caller can call `errno`‑style
        // inspection if desired.
        return nullptr;
    }
}

extern "C" void bs_iter_free(bs_iter_t *it) {
    delete it;   // unique_ptr cleans everything up
}

/* --------------------------------------------------------------------
   Accessors – simple inline wrappers around the underlying BlockSci API.
   -------------------------------------------------------------------- */
extern "C" uint32_t bs_block_height(const bs_block_t *blk) {
    return static_cast<uint32_t>(blk->ptr->height);
}
extern "C" uint64_t bs_block_timestamp(const bs_block_t *blk) {
    return static_cast<uint64_t>(blk->ptr->timestamp);
}
extern "C" const char *bs_block_hash_hex(const bs_block_t *blk) {
    // BlockSci stores the hash as a 32‑byte array; we expose a static
    // hex string that lives as long as the iterator.
    static thread_local char hex[65];
    const auto &h = blk->ptr->hash;   // assume std::array<uint8_t,32>
    for (size_t i = 0; i < 32; ++i)
        std::sprintf(hex + i * 2, "%02x", h[i]);
    hex[64] = '\0';
    return hex;
}
extern "C" size_t bs_block_tx_count(const bs_block_t *blk) {
    return blk->ptr->txes.size();
}

/* --------------------------------------------------------------------
   Core iteration routine – the hot path.
   -------------------------------------------------------------------- */
extern "C" int bs_iterate_blocks(bs_iter_t *it, bs_block_cb cb, void *user_data) {
    if (!it || !cb) return -1;                     // bad arguments

    try {
        for (; it->cur != it->end; ++it->cur) {
            // Populate the view once per iteration – no allocation.
            it->view.ptr = &*it->cur;              // dereference iterator

            int rc = cb(&it->view, user_data);     // invoke user code
            if (rc != 0) {
                // Propagate user‑requested abort (positive) or
                // unexpected negative code unchanged.
                return rc;
            }
        }
        return 0;   // normal completion
    } catch (...) {
        return translate_exception("bs_iterate_blocks");
    }
}

/* --------------------------------------------------------------------
   Optional debug helper – only compiled when BLOCKSCI_C_EXPOSE_INTERNALS
   is defined by the user.
   -------------------------------------------------------------------- */
#ifdef BLOCKSCI_C_EXPOSE_INTERNALS
extern "C" void *bs_block_internal_ptr(const bs_block_t *blk) {
    return const_cast<blocksci::Block*>(blk->ptr);
}
#endif

/* --------------------------------------------------------------------
   End of file
   -------------------------------------------------------------------- */
```

